public class Solution {
    public int findPairs(int[] nums, int k) {
        if (k < 0) return 0;

        // Use a stream to process the array
        return Arrays.stream(nums)
            .distinct() // Remove duplicates for accurate counting
            .filter(num -> occurrences.containsKey(num + k))
            .count();
    }
}

