public class Solution {

    public int diameterOfBinaryTree(TreeNode root) {
        if (root == null) return 0;

        int[] result = new int[1];
        helper(root, result);
        return result[0] - 1; // Subtract 1 because the height is one-based
    }

    private void helper(TreeNode node, int[] result) {



        int leftHeight = getHeight(node.left);
        int rightHeight = getHeight(node.right);

        result[0] = Math.max(result[0], leftHeight + rightHeight + 1); // Update the diameter

        helper(node.left, result);
        helper(node.right, result);
    }

    private int getHeight(TreeNode node) {



        int leftHeight = getHeight(node.left);
        int rightHeight = getHeight(node.right);

        return Math.max(leftHeight, rightHeight) + 1; // Return the height of this subtree
    }
}

