import java.util.*;

public class Solution {
    public String splitLoopedString(String[] strs) {
        int i = 0, k = 0;
        return solve(strs);
    }

    private String solve(String[] strs) {
        String ans = "", cur = "";
        for (String s : strs) {
            String rev = new StringBuilder(s).reverse().toString();
            cur += (s.compareTo(rev) > 0) ? s : rev;
        }

        return max(ans, maxLoop(cur));
    }

    private String max(String a, String b) {
        if (a == null || a.length() < b.length()) {
            return b;
        } else {
            return a;
        }
    }

    private String maxLoop(String cur) {
        StringBuilder ans = new StringBuilder();

        for (int i = 0; i < strs.length; i++) {
            String rev = new StringBuilder(strs[i]).reverse().toString();

            for (String xstr : Arrays.asList(strs[i], rev)) {
                for (int j = 0; j < xstr.length(); j++) {
                    ans.append(xstr.substring(j));
                    if (i == strs.length - 1 && k + xstr.length() >= cur.length()) {
                        break;
                    }

                    String t = ans.toString();
                    int len = t.length(), endLen = cur.length() - len, startLen = j;
                    for (; i < strs.length; i++) {
                        if (startLen > 0 && !t.substring(startLen).equals(strs[i].substring(0))) continue;

                        String nextStr = k + xstr.length() >= cur.length() ? rev : t.substring(endLen);
                        ans.append(nextStr);

                        len += nextStr.length();
                        startLen = endLen;

                        if (i == strs.length - 1 && j < xstr.length()) {
                            break;
                        }
                    }

                    k += strs[i].length();

                    ans.delete(startLen, ans.length());
                }
            }
        }

        return ans.toString();
    }
}
