public class Solution {
    public String splitLoopedString(String[] strs) {
        return new StringBuilder(splitLoopedStringHelper(strs)).reverse().toString();
    }

    private String splitLoopedStringHelper(String[] strs) {
        String ans = "", cur = "";
        for (String s : strs) {
            String rev = new StringBuilder(s).reverse().toString();
            if (s.compareTo(rev) > 0) cur += s;
            else cur += rev;
        }

        return max(ans, helper(strs, cur));
    }

    private String max(String a, String b) {
        return a.compareTo(b) > 0 ? a : b;
    }    

    private String helper(String[] strs, String cur) {
        if (strs.length == 0) return cur;

        StringBuilder ans = new StringBuilder(cur);

        for (int i = 0; i < strs.length; i++) {
            String rev = new StringBuilder(strs[i]).reverse().toString();

            for (String xstr : Arrays.asList(strs[i], rev)) {                
                if (xstr.compareTo(ans) > 0) ans.setLength(0);

                for (int j = 0; j < xstr.length(); j++) {
                    String t = new StringBuilder(xstr.substring(j)).append(cur).toString();

                    if (t.compareTo(ans) > 0) ans.setLength(t.length());
                }
            }            
        }

        return ans.toString();
    }
}
