import java.util.*;

public class Solution {
    public String splitLoopedString(String[] strs) {
        return splitAndCompare(strs);
    }

    private String splitAndCompare(String[] strs) {
        StringBuilder cur = new StringBuilder();

        for (String s : strs) {
            String rev = new StringBuilder(s).reverse().toString();

            if (s.compareTo(rev) > 0) 
                cur.append(s); 
            else
                cur.append(rev);
        }

        return maxPermutation(cur.toString());
    }

    private String maxPermutation(String str) {
        char[] chars = str.toCharArray();
        Arrays.sort(chars);

        for (int i = 0; i < chars.length - 1; i++) {
            if (chars[i] != '9') {
                int j = findNextMaxIndex(chars, i + 1);
                swap(chars, i, j);
                break;
            }
        }

        return new String(chars);
    }

    private void swap(char[] arr, int i, int j) {
        char temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }

    private int findNextMaxIndex(char[] chars, int start) {
        for (int i = chars.length - 1; i >= start; i--) {
            if (chars[start] < chars[i]) return i;
        }

        throw new IllegalArgumentException("No next max index found");
    }
}

