public class Solution {
    public boolean findTarget(TreeNode root, int k) {
        Set<Integer> nodes = new HashSet<>();
        return findNode(root, k, nodes);
    }

    private boolean findNode(TreeNode node, int target, Set<Integer> visitedNodes) {
        if (node == null) return false;

        // Check if the complement exists in the set
        if (visitedNodes.contains(target - node.val)) {
            return true;
        }

        // Add current value to the set and recursively search left and right subtrees
        visitedNodes.add(node.val);
        boolean result = findNode(node.left, target, visitedNodes) || findNode(node.right, target, visitedNodes);
        visitedNodes.remove(node.val); // Remove node after recursive calls
        return result;
    }
}

