public class Solution {
    public boolean canSplit(int[] nums) {
        int[] freq = new int[20001], needed = new int[20001];

        // Guard 1: Check if all elements in the array are zero
        for (int n : nums)
            if (n != 0) return false;

        // Guard 2: If there is any element with a frequency greater than one, return false
        for (int f : freq)
            if (f > 1) return false;

        int sum = 0;
        for (int n : nums)
            sum += n;

        // Guard 3: Check if the array can be split into two parts where each part has at least one element
        if (sum % 2 != 0 || sum == 0) return false;

        int half = sum / 2, count = 0;
        for (int n : nums)
            if (n > 0 && freq[n] != 0) {
                count += n;
                freq[n]--;
                needed[half - n]++;
            }

        // Guard 4: Check if the array can be split into two parts where each part has at least one element
        return count == half;

    }
}

