public class Solution {
    public int countCornerRectangles(int[][] grid) {
        int count = 0;
        int m = grid.length;
        int n = grid[0].length;

        for (int i = 0; i < m - 1; i++) {
            boolean[] rowSet = new boolean[n];
            for (int j = 0; j < n; j++) {
                if (grid[i][j] == 1) {
                    rowSet[j] = true;
                }
            }

            for (int k = i + 1; k < m; k++) {
                int cornerCount = 0;
                boolean[] colSet = new boolean[n];
                for (int l = 0; l < n; l++) {
                    if (grid[k][l] == 1 && rowSet[l]) {
                        cornerCount++;
                        colSet[l] = true;
                    }
                }

                count += cornerCount * (cornerCount - 1) / 2;
            }
        }
        return count;
    }
}

