public class Solution {
    public int fixedPoint(int[] arr) {
        int left = 0, right = arr.length - 1;
        while (left < right) {
            int middle = left + (right - left) / 2;
            if (arr[middle] < middle) {
                left = middle + 1;
            } else {
                right = middle;
            }
        }
        return arr[left] == left ? left : -1;
    }
}

