    public int countDigit(int d, int low, int high) {
        int count = 0;
        for (int i = low; i <= high; i++) {
            int num = i;
            while (num > 0) {
                if (num % 10 == d) {
                    count++;
                }
                num /= 10;
            }
        }
        return count;
    }
}

