public class Solution {
    public int countDigit(int d, int low, int high) {
        return computeCountDigit(d, low, high);
    }

  private static int computeCountDigit(int digit, int lowerBound, int upperBound) {
        int totalCount = 0;

        for (int number = lowerBound; number <= upperBound; number++) {
            if (containsDigit(number, digit)) {
                totalCount++;
            }
        }

        return totalCount;
    }

    private static boolean containsDigit(int num, int targetDigit) {
        while (num > 0) {
            if (num % 10 == targetDigit) {
                return true;
            }
            num /= 10;
        }
        return false;
    }
}

