public class Solution {
    public int maxSumUnderK(int[] nums, int k) {
        int maxSum = -1;
        for (int i = 0; i < nums.length; i++) {
            for (int j = i + 1; j < nums.length; j++) {
                int sum = nums[i] + nums[j];
                if (sum < k && sum > maxSum) {
                    maxSum = sum;
                }
            }
        }
        return maxSum;
    }
}

